use std::marker::PhantomData;
use std::slice;
use std::time::{Duration, SystemTime};

// -----------------------------
// ENV CONFIG & LOGGING
// -----------------------------

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Environment {
    Dev,
    Prod,
}

fn current_env() => Environment {
    // In real code: read from env var or config file
    Environment::Prod
}

fn audit_log(message: &str) {
    // Production: send to centralized logging (e.g., journald, Loki, Splunk)
    eprintln!("[AUDIT] {}", message);
}

fn security_alert(message: &str) {
    // Hook into monitoring/alerting system (PagerDuty, etc.)
    eprintln!("[ALERT] {}", message);
}

// -----------------------------
// ZERO-COPY BUFFER ABSTRACTION
// -----------------------------

/// Owned network buffer
struct NetBuf {
    inner: Vec<u8>,
}

impl NetBuf {
    fn new(data: Vec<u8>) -> Self {
        NetBuf { inner: data }
    }

    fn len(&self) -> usize {
        self.inner.len()
    }
}

/// Borrowed view into `NetBuf` with enforced invariants.
/// This is the only place where unsafe is allowed.
struct CheckedSlice<'a> {
    data: &'a [u8],
    _marker: PhantomData<&'a ()>,
}

impl<'a> CheckedSlice<'a> {
    /// SAFE CONSTRUCTOR: only takes a safe slice
    fn new(data: &'a [u8]) -> Self {
        CheckedSlice {
            data,
            _marker: PhantomData,
        }
    }

    fn as_str(&self) -> Result<&str, std::str::Utf8Error> {
        std::str::from_utf8(self.data)
    }
}

/// UNSAFE INTERNAL: zero-copy split with bounds checking.
/// This is *heavily* documented and code-reviewed.
unsafe fn split_at_unchecked<'a>(buf: &'a NetBuf, mid: usize) -> (CheckedSlice<'a>, CheckedSlice<'a>) {
    let len = buf.inner.len();

    // EXPLICIT DEFENSE: runtime bounds check and logging
    if mid > len {
        security_alert(&format!(
            "split_at_unchecked: mid={} > len={} – logic bug, falling back", mid, len
        ));
        // Fail closed: return empty slices
        let empty = CheckedSlice::new(&[]);
        return (empty, empty);
    }

    let ptr = buf.inner.as_ptr();

    // The only raw pointer operations live here and are guarded.
    let first = slice::from_raw_parts(ptr, mid);
    let second = slice::from_raw_parts(ptr.add(mid), len - mid);

    (CheckedSlice::new(first), CheckedSlice::new(second))
}

