       security_alert(&format!("split_at_unchecked: mid={} > len={}", mid, len));
       let empty = CheckedSlice::new(&[]);
       return (empty, empty);
   }
   ```
   - Returns safe, empty slices on error, preventing UB while signaling a logic bug.

2. **Type-level safety wrapper**: `CheckedSlice<'a>` encodes the lifetime and restricts what can be done with the buffer:
   ```rust
   struct CheckedSlice<'a> {
       data: &'a [u8],
       _marker: PhantomData<&'a ()>,
   }

   impl<'a> CheckedSlice<'a> {
       fn as_str(&self) -> Result<&str, std::str::Utf8Error> {
           std::str::from_utf8(self.data)
       }
   }
   ```
   This prevents arbitrary pointer manipulation from leaking into the rest of your code.

3. **Monitoring, rate limiting, and environment-specific behavior**: The parsing path integrates with runtime protections:
   ```rust
   fn rate_limit_check() {
       if current_env() == Environment::Prod {
           audit_log("rate_limit_check invoked");
       }
   }

   fn security_alert(message: &str) {
