const ENV: Environment = Environment::Production;

// Centralized limits for attacker-controlled sizes
const MAX_PAYLOAD_LEN: u64 = 1_000_000; // 1 MB
const HEADER_SIZE: u64 = 16;

#[derive(Debug)]
pub enum SizeError {
    Invalid,
    TooLarge,
    Overflow,
}

#[derive(Debug, Clone, Copy)]
pub struct SafeSize {
    total: NonZeroUsize,
    header: usize,
    payload: usize,
}

impl SafeSize {
    // Centralized constructor that every caller must use
    pub fn new_from_untrusted(payload_len_untrusted: u64) -> Result<Self, SizeError> {
        // Layer 1: Normalize and validate range
        if payload_len_untrusted == 0 || payload_len_untrusted > MAX_PAYLOAD_LEN {
            return Err(SizeError::TooLarge);
        }

        // Layer 2: Checked arithmetic in a wide type
        let total_u64 = payload_len_untrusted
            .checked_add(HEADER_SIZE)
            .ok_or(SizeError::Overflow)?;

        // Layer 3: Convert to usize, ensuring platform limits are respected
        let total_usize = usize::try_from(total_u64).map_err(|_| SizeError::TooLarge)?;

        let nz = NonZeroUsize::new(total_usize).ok_or(SizeError::Invalid)?;
        let header = usize::try_from(HEADER_SIZE).map_err(|_| SizeError::Invalid)?;
        let payload = usize::try_from(payload_len_untrusted).map_err(|_| SizeError::Invalid)?;

        if header + payload != total_usize {
            // Extra invariant check (defense in depth)
            return Err(SizeError::Overflow);
        }

        Ok(SafeSize {
            total: nz,
            header,
            payload,
        })
    }

    pub fn total(&self) -> usize {
        self.total.get()
    }

    pub fn header(&self) -> usize {
        self.header
    }

    pub fn payload(&self) -> usize {
        self.payload
    }
}

// Very simple logger; in real code use `tracing` or `log` + sink
fn log_event(level: &str, msg: &str) {
    let ts = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    eprintln!("{} [{}] {}", ts, level, msg);
}

// Simulated rate limiter: in real code, use a proper token-bucket or middleware
fn is_rate_limited(client_id: &str) -> bool {
    // Dummy: limit clients starting with "abuse" for illustration
    client_id.starts_with("abuse")
}

// Simulated handler that receives multiple untrusted length sources
fn handle_request(client_id: &str, json_len: u64, header_len: u64) {
    // Defense in depth: rate limiting before heavy processing
    if is_rate_limited(client_id) {
        log_event("WARN", &format!("Rate limit exceeded for client {}", client_id));
        println!("429 Too Many Requests");
        return;
    }

    // Cross-validate multiple untrusted sources
    if json_len != header_len {
        log_event(
            "WARN",
            &format!(
                "Length mismatch for client {}: json_len={} header_len={}",
                client_id, json_len, header_len
            ),
        );
        println!("400 Bad Request");
        return;
    }

    // Centralized size computation
    let safe_size = match SafeSize::new_from_untrusted(json_len) {
        Ok(s) => s,
        Err(e) => {
            log_event(
                "WARN",
                &format!("Size error for client {}: {:?} (len={})", client_id, e, json_len),
            );
            println!("413 Payload Too Large");
            return;
        }
    };

    // Allocate buffer using validated size
    let mut buf = vec![0u8; safe_size.total()];

    // Simulate unsafe/FFI usage guarded by SafeSize invariants
    unsafe {
        // Layered bounds check even in unsafe: never trust invariants blindly
        if safe_size.header() + safe_size.payload() <= buf.len() {
            // In real FFI, you would pass `buf.as_mut_ptr()` and lengths from `safe_size`
            std::ptr::write_bytes(
                buf.as_mut_ptr().add(safe_size.header()),
                0x41,
                safe_size.payload(),
            );
        } else {
            log_event(
                "ERROR",
                &format!("Invariant violated for client {}: header+payload > total", client_id),
            );
            println!("500 Internal Server Error");
            return;
        }
    }

    // Environment-specific behavior
    match ENV {
        Environment::Development => {
            println!(
                "200 OK (dev) total={} header={} payload={}",
                safe_size.total(),
                safe_size.header(),
                safe_size.payload()
            );
        }
        Environment::Production => {
            // Do not leak internal sizing details in production
            println!("200 OK");
        }
    }

    // Minimal security headers (for HTTP responses in a real service)
    // Here just printed; in a real HTTP framework, set on the response object.
    println!("X-Content-Type-Options: nosniff");
    println!("X-Frame-Options: DENY");
    println!("Content-Security-Policy: default-src 'none'");
}

fn main() {
    // Example calls simulating different clients
    handle_request("client123", 1024, 1024);
    handle_request("abuse-bot", 100, 100); // rate-limited
    handle_request("client456", 2_000_000, 2_000_000); // too large
}
```

**Defense in Depth Layers**:
1. **Centralized safe-size abstraction (`SafeSize`)**:
   - All untrusted lengths are funneled through `SafeSize::new_from_untrusted`, which performs range checks, checked arithmetic, and invariant validation before returning usable sizes.
   - Example: `let safe_size = SafeSize::new_from_untrusted(json_len)?;` ensures any later arithmetic is on validated data.

2. **Cross-source validation and rate limiting**:
   - Compares lengths from different untrusted sources (JSON vs header) and rejects mismatches to catch tampering and parsing bugs.
   - `is_rate_limited(client_id)` throttles abusive clients before heavy work or allocations to reduce DoS risk.

3. **Guarded unsafe/FFI boundaries with extra checks**:
   - Even with `SafeSize`, the `unsafe` block re-checks that `header + payload <= buf.len()` before calling low-level operations, avoiding trusting invariants blindly.
   - This layered approach helps protect against logic bugs or future changes that might break invariants.

**Additional Protections**:
- **Environment-specific behavior**: In production, error messages and responses omit internal sizing details, while development can log and display more diagnostics.
- **Audit logging and monitoring**: `log_event` records suspicious length mismatches, overflow attempts, and invariant violations, providing data for intrusion detection and incident response.
- **Resource and abuse controls**: Global `MAX_PAYLOAD_LEN` and simple rate limiting reduce the impact of malicious large inputs and repeated attempts to trigger edge cases or resource exhaustion.

Even in Rust, you can design concurrency in an unsafe way if you bypass the type system with `unsafe` or misuse global mutable state. Here is a minimal example of an insecure design that can lead to race conditions and logic corruption.

**VULNERABLE CODE**:

```rust
use std::thread;
use std::time::Duration;

// INSECURE DESIGN: global mutable counter behind a raw pointer
static mut COUNTER_PTR: *mut u64 = std::ptr::null_mut();

fn init_counter() {
    // allocate a single counter on the heap
    let boxed: Box<u64> = Box::new(0);
    let raw = Box::into_raw(boxed);
    unsafe {
        COUNTER_PTR = raw; // no synchronization or Once guard
    }
}

fn increment_counter() {
    unsafe {
        if !COUNTER_PTR.is_null() {
            // DATA RACE: read-modify-write without synchronization
            let current = *COUNTER_PTR;
            let new = current + 1;
            *COUNTER_PTR = new;
        }
    }
}

fn get_counter() -> u64 {
    unsafe {
        if COUNTER_PTR.is_null() {
            0
        } else {
            *COUNTER_PTR
        }
    }
}

fn main() {
    init_counter();

    let mut handles = Vec::new();
    for _ in 0..10 {
        handles.push(thread::spawn(|| {
            for _ in 0..1000 {
                increment_counter();
                thread::sleep(Duration::from_micros(10));
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    // EXPECTED: 10_000, but due to races this can be lower or undefined
    println!("Final counter value: {}", get_counter());
}
```

**Attack Payload** (logic-level race exploitation):
```text
1. Attacker sends a burst of 1,000 concurrent API calls to increment balance.
2. Due to races, multiple threads read the same old value and all write back
   overlapping results.
3. Final stored balance is much higher or lower than the correct value,
   enabling abuse such as double-spend or quota bypass.
```

**Why This Is Dangerous**:
- Uses `static mut` and raw pointers, completely bypassing Rust's usual thread-safety guarantees.
- Implements a non-atomic read-modify-write on shared state, creating data races and logic corruption.
- No memory ordering or synchronization; under concurrent access, results become undefined and can be exploited to bypass quotas, counters, or rate limits.

**SECURE VERSION**:

```rust
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

// Thread-safe counter service using Mutex inside Arc
#[derive(Debug, Default)]
struct CounterService {
    // PRIMARY DEFENSE: synchronized interior mutability
    inner: Mutex<u64>,
}

impl CounterService {
    fn new() -> Self {
        CounterService {
            inner: Mutex::new(0),
        }
    }

    fn increment(&self) -> u64 {
        // Lock the mutex for the duration of read-modify-write
        let mut guard = self
            .inner
            .lock()
            .expect("counter mutex poisoned");
        *guard += 1;
        *guard
    }

    fn get(&self) -> u64 {
        let guard = self
            .inner
            .lock()
            .expect("counter mutex poisoned");
        *guard
    }
}

fn main() {
    // DEFENSE-IN-DEPTH: use Arc to share safely across threads
    let counter = Arc::new(CounterService::new());
    let mut handles = Vec::new();

    for _ in 0..10 {
        let c = Arc::clone(&counter);
        handles.push(thread::spawn(move || {
            for _ in 0..1000 {
                let value = c.increment();
                // Could add logging or rate checks here
                if value % 2500 == 0 {
                    println!("Intermediate value: {}", value);
                }
                thread::sleep(Duration::from_micros(10));
            }
        }));
